class TreeNode {
    constructor(val, left = null, right = null) {
        this.val = val;
        this.left = left;
        this.right = right;
    }
}

function longestConsecutivePath(root) {
    function longestConsecutivePathUtil(node, maxLength) {
        if (!node) {
            return 0;
        }
        let left = longestConsecutivePathUtil(node.left, maxLength) + 1;
        let right = longestConsecutivePathUtil(node.right, maxLength) + 1;
        if (node.left && node.left.val !== node.val + 1) {
            left = 1;
        }
        if (node.right && node.right.val !== node.val + 1) {
            right = 1;
        }
        let length = Math.max(left, right);
        maxLength[0] = Math.max(maxLength[0], left + right - 1);
        return length;
    }

    let maxLength = [0];
    longestConsecutivePathUtil(root, maxLength);
    return maxLength[0];
}
```

    The algorithm starts traversing the tree in a depth first search (DFS) from the root till each of the leafs. For each consecutive increasing path, it increments the length by one. If a node value breaks the consecutive sequence, it resets the length of that subtree. It keeps track of the maximum length of the consecutive path found so far in any of the subtrees, and updates it when it finds a longer path. Finally, it returns that value.

